import {
  STROKE_ONLY_OPACITY_BAND_CHART,
  DEFAULT_OPACITY_BAND_CHART,
} from '../../../../core/constants.js';
import { ShapeColor } from '../../../../core/types/color-palette.js';
import { SeriesMetadata } from '../../../types/timeseries.js';

export const getBandStyle = (
  seriesMetadata: SeriesMetadata,
  strokeOnly?: boolean,
): Required<ShapeColor> => {
  if (strokeOnly) {
    return {
      color: 'transparent',
      stroke: seriesMetadata.color.Default,
      opacity: STROKE_ONLY_OPACITY_BAND_CHART,
    };
  }

  return {
    color: seriesMetadata.color.Default,
    stroke: seriesMetadata.color.Default,
    opacity: DEFAULT_OPACITY_BAND_CHART,
  };
};
